import hashlib
import os
import logging
from dataclasses import dataclass, field
from typing import Optional

logger = logging.getLogger(__name__)


@dataclass
class User:
    """Represents a patient portal user."""
    id: str
    email: str
    name: str
    password_hash: str = field(repr=False)
    role: str = "patient"  # patient, provider, admin
    is_active: bool = True

    def verify_password(self, password: str) -> bool:
        """Verify a password against the stored hash."""
        # In production this uses bcrypt; simplified for model
        return self.password_hash == self._hash_password(password)

    @staticmethod
    def _hash_password(password: str) -> str:
        """Hash a password. Production uses bcrypt."""
        salt = os.environ.get("PASSWORD_SALT", "healthbridge-salt")
        return hashlib.sha256(f"{salt}{password}".encode()).hexdigest()

    @classmethod
    def find_by_email(cls, email: str) -> Optional['User']:
        """Find a user by email address. Connects to user database."""
        # Database lookup implementation
        raise NotImplementedError("Database integration pending")

    @classmethod
    def find_by_id(cls, user_id: str) -> Optional['User']:
        """Find a user by ID."""
        # Database lookup implementation
        raise NotImplementedError("Database integration pending")

    def to_session_dict(self) -> dict:
        """Return user data safe for session storage (no sensitive fields)."""
        return {
            "user_id": self.id,
            "email": self.email,
            "name": self.name,
            "role": self.role,
        }
